 1	import * as React from 'react';
 2	import { connect } from 'react-redux';
 3	import { KialiDispatch } from 'types/Redux';
 4	import { Card, Button, CardBody, CardFooter, ButtonVariant } from '@patternfly/react-core';
 5	import { InfoIcon } from '@patternfly/react-icons';
 6	import { kialiStyle } from 'styles/StyleUtils';
 7	import { NotificationGroup } from '../../types/MessageCenter';
 8	import { MessageCenterThunkActions } from 'actions/MessageCenterThunkActions';
 9	import { AlertDrawerMessage } from './AlertDrawerMessage';
10	
11	type ReduxProps = {
12	  clearGroup: (group) => void;
13	  markGroupAsRead: (group) => void;
14	};
15	
16	type AlertDrawerGroupProps = ReduxProps & {
17	  group: NotificationGroup;
18	  reverseMessageOrder?: boolean;
19	};
20	
21	const noNotificationsMessage = (
22	  <>
23	    <InfoIcon />
24	    No Messages Available
25	  </>
26	);
27	
28	class AlertDrawerGroupComponent extends React.PureComponent<AlertDrawerGroupProps> {
29	  static readonly body = kialiStyle({
30	    padding: 0 // note: I don't know why but paddingTop with the additional explicit style prop used below
31	  });
32	  static readonly footer = kialiStyle({
33	    paddingBottom: 5,
34	    paddingTop: 5
35	  });
36	  static readonly left = kialiStyle({
37	    float: 'left'
38	  });
39	  static readonly right = kialiStyle({
40	    float: 'right'
41	  });
42	
43	  render() {
44	    const group: NotificationGroup = this.props.group;
45	
46	    return (
47	      <Card>
48	        <CardBody className={AlertDrawerGroupComponent.body} style={{ paddingTop: 0 }}>
49	          {group.messages.length === 0 && noNotificationsMessage}
50	          {this.getMessages().map(message => (
51	            <AlertDrawerMessage key={message.id} message={message} />
52	          ))}
53	        </CardBody>
54	        {group.showActions && group.messages.length > 0 && (
55	          <CardFooter className={AlertDrawerGroupComponent.footer}>
56	            <Button
57	              className={AlertDrawerGroupComponent.left}
58	              variant={ButtonVariant.link}
59	              onClick={() => this.props.markGroupAsRead(group)}
60	            >
61	              Mark All Read
62	            </Button>
63	            <Button
64	              className={AlertDrawerGroupComponent.right}
65	              variant={ButtonVariant.link}
66	              onClick={() => this.props.clearGroup(group)}
67	            >
68	              Clear All
69	            </Button>
70	          </CardFooter>
71	        )}
72	      </Card>
73	    );
74	  }
75	
76	  private getMessages = () => {
77	    return this.props.reverseMessageOrder ? [...this.props.group.messages].reverse() : this.props.group.messages;
78	  };
79	}
80	
81	const mapDispatchToProps = (dispatch: KialiDispatch) => {
82	  return {
83	    clearGroup: group => dispatch(MessageCenterThunkActions.clearGroup(group.id)),
84	    markGroupAsRead: group => dispatch(MessageCenterThunkActions.markGroupAsRead(group.id))
85	  };
86	};
87	
88	export const AlertDrawerGroup = connect(null, mapDispatchToProps)(AlertDrawerGroupComponent);

